import {
    IMessageDataWrapper,
    IMessageParser,
} from '@nitrots/nitro-renderer/src/core';

export class ClickThroughStateParser implements IMessageParser {
    private _enabled = false;

    public flush(): boolean {
        this._enabled = false;
        return true;
    }

    public parse(wrapper: IMessageDataWrapper): boolean {
        if (!wrapper) return false;

        this._enabled = wrapper.readBoolean();

        // Optional quality-of-life: reflect global + CSS class for UI
        (window as any).__ctEnabled = this._enabled;
        document.documentElement.classList.toggle('ct-on', this._enabled);

        // Bridge to app/UI
        window.dispatchEvent(
            new CustomEvent('click_through_state', {
                detail: { enabled: this._enabled },
            })
        );

        return true;
    }

    public get enabled(): boolean {
        return this._enabled;
    }
}
